  ctx.fillStyle = '#3d0a6b';
  ctx.fillRect(cx - 4, cy - 9, 9, 10);
  // Lower robe flare
  ctx.fillStyle = '#2d0855';
  ctx.fillRect(cx - 6, cy + 1, 13, 10);
  // Robe hem
  ctx.fillStyle = '#1a033a';
  ctx.fillRect(cx - 8, cy + 11, 17, 5);
  // Feet
  ctx.fillStyle = '#150228';
  ctx.fillRect(cx - 7, cy + 16, 5, 4);
  ctx.fillRect(cx + 2, cy + 16, 5, 4);
  // Arms
  ctx.fillStyle = '#4a0e8f';
  ctx.fillRect(cx - 9, cy - 8, 5, 9);
  ctx.fillRect(cx + 5, cy - 8, 5, 9);
  // Hands
  ctx.fillStyle = '#d4a574';
  ctx.fillRect(cx - 8, cy + 1, 3, 3);
  ctx.fillRect(cx + 6, cy + 1, 3, 3);
  // Left energy orb (magenta)
  ctx.fillStyle = '#ff00ff';
  ctx.fillRect(cx - 11, cy - 1, 4, 4);
  ctx.fillStyle = '#ffaaff';
  ctx.fillRect(cx - 10, cy, 2, 2);
  // Right energy orb (cyan)
  ctx.fillStyle = '#00ccff';
  ctx.fillRect(cx + 8, cy - 1, 4, 4);
  ctx.fillStyle = '#aaeeff';
