// Shuffling Card Swarm: scattered playing cards fanning outward in a chaotic swarm
function drawSprite_shuffling_card_swarm(ctx, cx, cy) {
  var cards = [
    { dx: -9, dy: -18, suit: '#cc2222', face: true },
    { dx: 3,  dy: -15, suit: '#111188', face: false },
    { dx: -7, dy: -7,  suit: '#cc2222', face: true },
    { dx: 5,  dy: -5,  suit: '#111188', face: false },
    { dx: -8, dy: 4,   suit: '#111133', face: true },
    { dx: 4,  dy: 7,   suit: '#cc2222', face: false },
    { dx: -4, dy: 14,  suit: '#cc2222', face: true },
    { dx: 6,  dy: 12,  suit: '#111188', face: false },
  ];
  var cw = 7, ch = 10;
  for (var i = 0; i < cards.length; i++) {
    var c = cards[i];
    var x = Math.floor(cx + c.dx);
    var y = Math.floor(cy + c.dy);
    ctx.fillStyle = '#1a1a2e';
    ctx.fillRect(x - 1, y - 1, cw + 2, ch + 2);
    if (c.face) {
      ctx.fillStyle = '#f5f0e8';
      ctx.fillRect(x, y, cw, ch);
      ctx.fillStyle = c.suit;
      ctx.fillRect(x + 2, y + 2, 3, 2);
      ctx.fillRect(x + 2, y + 6, 3, 2);
    } else {
      ctx.fillStyle = '#2244aa';
      ctx.fillRect(x, y, cw, ch);
      ctx.fillStyle = '#3366cc';
      ctx.fillRect(x + 1, y + 1, cw - 2, ch - 2);
      ctx.fillStyle = '#1133aa';
      ctx.fillRect(x + 2, y + 2, 3, 6);
    }
  }
  ctx.fillStyle = '#ffcc00';
  ctx.fillRect(cx - 1, cy - 1, 3, 3);
}
window.drawSprite_shuffling_card_swarm = drawSprite_shuffling_card_swarm;


